class Solution:
    def isIdealPermutation(self, nums):
        """
        :type nums: List[int]
        :rtype: bool
        """
        # Local inversions are when nums[i] > nums[i+1]
        # All global inversions must be local
        # This means no element can be more than 1 position away from its target

        for i in range(len(nums)):
            if abs(nums[i] - i) > 1:
                return False
        return True
